import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate investment returns?", a: "Investment returns are calculated by growing the initial investment and each contribution by the expected return over time, then subtracting total contributions from the final value." },
  { q: "What is compound growth?", a: "Compound growth means your earnings can generate more earnings. Over long periods, this can make returns grow faster than simple interest." },
  { q: "What is a realistic expected return on investments?", a: "A realistic return depends on asset type, risk, and time horizon. Broad stock market assumptions often use 6% to 10% annually for long-term planning, but actual returns vary." },
  { q: "How much should you invest each month?", a: "Many people start with a percentage of income, such as 10% to 20%, while keeping emergency savings and debt goals in mind." },
  { q: "What is the difference between investing and saving?", a: "Saving is usually for short-term safety and liquidity. Investing accepts more risk in exchange for the potential of higher long-term growth." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });

function futureValue(initial: number, monthly: number, annualReturn: number, years: number, compoundsPerYear: number) {
  const periods = Math.max(0, Math.round(years * compoundsPerYear));
  const periodicRate = annualReturn / 100 / compoundsPerYear;
  const monthlyRate = annualReturn / 100 / 12;
  const initialGrowth = initial * Math.pow(1 + periodicRate, periods);
  const contributionGrowth = monthlyRate === 0 ? monthly * years * 12 : monthly * ((Math.pow(1 + monthlyRate, years * 12) - 1) / monthlyRate);
  return initialGrowth + contributionGrowth;
}

export default function InvestmentCalculator() {
  useCurrencyVersion();
  const [initial, setInitial] = useState(10000);
  const [monthly, setMonthly] = useState(500);
  const [annualReturn, setAnnualReturn] = useState(8);
  const [years, setYears] = useState(20);
  const [frequency, setFrequency] = useState(12);

  const finalValue = futureValue(initial, monthly, annualReturn, years, frequency);
  const totalContributions = initial + monthly * years * 12;
  const interestEarned = finalValue - totalContributions;
  const growthRows = useMemo(() => Array.from({ length: years + 1 }, (_, year) => {
    const value = futureValue(initial, monthly, annualReturn, year, frequency);
    const contributed = initial + monthly * year * 12;
    return { year, value, contributed, interest: value - contributed };
  }), [initial, monthly, annualReturn, years, frequency]);
  const comparisonRows = [4, 6, 8, 10, 12].map((rate) => ({
    rate,
    y10: futureValue(10000, 500, rate, 10, 12),
    y20: futureValue(10000, 500, rate, 20, 12),
    y30: futureValue(10000, 500, rate, 30, 12),
    contributions: 10000 + 500 * 30 * 12,
  }));

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead title="Free Investment Calculator Online - Calculate Investment Growth and Returns Instantly | CalcHive" description="Free online investment calculator. Calculate investment growth, final value and total returns for any initial amount, monthly contribution and return rate instantly. 100% free, no signup required." canonical="/investment-calculator" keywords="free investment calculator, investment growth calculator free online, compound investment calculator free, calculate investment returns free, stock market investment calculator free" category="Financial Calculators" breadcrumbName="Free Investment Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Investment Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate investment growth, total contributions, and total returns from an initial amount, monthly contributions, return rate, and compounding frequency.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Initial investment</label><input type="number" min="0" value={initial} onChange={(e) => setInitial(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Monthly contribution</label><input type="number" min="0" value={monthly} onChange={(e) => setMonthly(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Expected annual return (%)</label><input type="number" min="0" step="0.1" value={annualReturn} onChange={(e) => setAnnualReturn(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Investment period (years)</label><input type="number" min="1" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Compounding frequency</label><select value={frequency} onChange={(e) => setFrequency(Number(e.target.value))} className={inputClass}><option value={1}>Annually</option><option value={4}>Quarterly</option><option value={12}>Monthly</option><option value={365}>Daily</option></select></div>
          </div>
          <motion.div key={`${initial}-${monthly}-${annualReturn}-${years}-${frequency}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Value</p><p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-investment">{money(finalValue)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Total Contributions", totalContributions], ["Interest Earned", interestEarned], ["Growth Multiple", totalContributions ? `${(finalValue / totalContributions).toFixed(2)}x` : "0x"]].map(([label, value]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">{label as string}</p><p className="text-lg font-extrabold text-foreground">{typeof value === "number" ? money(value) : value}</p></div>)}</div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Investment Growth and Returns for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This compound investment calculator free grows the starting balance and monthly deposits over the selected investment period.</p>
          <h2 className="text-2xl font-bold text-foreground">How Monthly Contributions Supercharge Your Investment</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Investment Growth on $10,000 Initial + $500/month at Different Returns</caption><thead className="bg-muted/60"><tr>{["Annual Return", "10 Years", "20 Years", "30 Years", "Total Contributions"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.rate} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold text-foreground">{row.rate}%</td><td className="py-2.5 px-3">{money(row.y10)}</td><td className="py-2.5 px-3">{money(row.y20)}</td><td className="py-2.5 px-3">{money(row.y30)}</td><td className="py-2.5 px-3">{money(row.contributions)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Compound Growth Investment Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Growth Table</caption><thead className="bg-muted/60"><tr>{["Year", "Total Contributions", "Interest Earned", "Portfolio Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{growthRows.map((row) => <tr key={row.year} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3">{money(row.contributed)}</td><td className="py-2.5 px-3 text-emerald-600 dark:text-emerald-400">{money(row.interest)}</td><td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{money(row.value)}</td></tr>)}</tbody></table></div>
        </section>

        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/investment-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


